s=open(p,encoding='utf-8').read()
before=len(s)
fails=[]
for old,new in REPL:
    c=s.count(old)
    if c==1: s=s.replace(old,new)
    else: fails.append((c, (old.splitlines() or [''])[0][:70]))
if fails:
    print('FAIL %d/%d:'%(len(fails),len(REPL)))
    for c,h in fails: print('  count=%d %s'%(c,h))
    sys.exit(1)
open(p,'w',encoding='utf-8',newline='').write(s)
print('OK applied %d hunks, size %d -> %d'%(len(REPL),before,len(s)))
